    String getCellName(int row, int cell){
        String cellName = "";
        int asciiCode = 65;     //A
        row = row + 1;
        if(cell<26){
            cellName = ""+(char)(asciiCode+cell)+row+"";
        } else {                            
            cellName = "A"+ (char)(asciiCode+(cell-26))+row+"";
        }
        return cellName;
    }
    
    String getWeekFromTo(int year, int mon, int week){
        String weekFromTo = "";
        Calendar c = new GregorianCalendar();
        c.set(Calendar.YEAR, year);
        c.set(Calendar.MONTH, mon);
        c.set(Calendar.WEEK_OF_MONTH, week);
        int dayOfWeek = c.get(Calendar.DAY_OF_WEEK); 
        Calendar calFirstDayInThisWeek = (Calendar)c.clone();
        calFirstDayInThisWeek.add(Calendar.DATE, c.getActualMinimum(Calendar.DAY_OF_WEEK)-dayOfWeek);
        Calendar calLastDayInThisWeek = (Calendar)c.clone();
        calLastDayInThisWeek.add(Calendar.DATE,c.getActualMaximum(Calendar.DAY_OF_WEEK)-dayOfWeek);
        weekFromTo = 
                 (calFirstDayInThisWeek.getTime().getYear()+1900)+"."+
                 (calFirstDayInThisWeek.getTime().getMonth()+1)+"."+
                 calFirstDayInThisWeek.getTime().getDate()+"~"+
                 (calLastDayInThisWeek.getTime().getYear()+1900)+"."+
                 (calLastDayInThisWeek.getTime().getMonth()+1)+"."+
                 calLastDayInThisWeek.getTime().getDate();
        return weekFromTo;
    }

 
    void addViewLog(String apName, String repName, String repType, String repYear, String repMon, String userId){
        final String AP_NAME = apName;        
        BDBWorker work4No = new BDBWorker(AP_NAME);        
        final int REC_NO = 1000173;
        final int REP_NAME = 1000174;
        final int REP_TYPE = 1000175;
        final int REP_YEAR = 1000176;
        final int REP_MON = 1000177;
        final int USER_ID = 1000178;
        final int VIEW_DATE = 1000179;
        final String DIAGEO_VIEW = "DiageoView";	//編流水號用
        int[] fieldId = {REC_NO, REP_NAME, REP_TYPE, REP_YEAR, REP_MON, USER_ID, VIEW_DATE};
        boolean[] ifMerge = {false, false, false, false, false, true, false};
        String[] recordValue = new String[7];                   
        try {            
            Calendar cal = Calendar.getInstance(); 
            cal.roll(Calendar.HOUR_OF_DAY,8);  //UTC+8小時
            recordValue[0] = String.valueOf(Encoder.incrementAutoGenerate("diageo",DIAGEO_VIEW));
            recordValue[1] = repName;
            recordValue[2] = repType;
            recordValue[3] = repYear;
            recordValue[4] = repMon;
            recordValue[5] = userId;
            recordValue[6] = cal.getTime().toString();            
        } catch (Exception e){
            e.printStackTrace();
        } finally {
            work4No.commit();                       
        }
        BDBSmartWorker worker = new BDBSmartWorker(AP_NAME);
        worker.addRecord(fieldId, recordValue, ifMerge);
    }
    
    boolean getViewLog(String apName, String repName, String userId){
        final String AP_NAME = apName;
        BDBWorker worker = new BDBWorker(AP_NAME);        
        final int REC_NO = 1000173;
        final int REP_NAME = 1000174;
        final int USER_ID = 1000178;        
        boolean isExist = false;
        try {
            SDBQuery q = new SDBQueryFull(worker);            
            q.go(REC_NO);//domain config name
            q.filter(REP_NAME,repName);
            q.filter(USER_ID,userId);
            isExist=q.next()!=null;            
        } catch (Exception e){
            e.printStackTrace();
        } finally {
            worker.commit();            
        }
        return isExist;
    }

